func:
// Discord Python 上線通知
// =========================

msg.headers = {
    "Content-Type": "application/json"
};

msg.url = "https://discord.com/api/webhooks/1507070766271959061/bAa1Pf55ixg0bJmqeoJTQVdPt2ScMyITxYr4ukHof8IfBUC6hCaQqysnqkn8paCXQcjO";

// =========================
// IP
// =========================
let ip = msg.payload?.ip || "未知IP";

// 保存 IP 到持久化全域 context，讓重連/重啟後仍可取用
try {
    global.set(
        "python_ip",
        ip,
        "file"
    );
} catch (e) {
    global.set(
        "python_ip",
        ip
    );
}

// =========================
// Discord Payload
// =========================
msg.payload = {

    username:
        "Cat Health Monitor",

    embeds: [

        {

            title:
                "🟢 Python AI 已上線",

            description:
                `偵測到 Python 推論系統啟動`,

            color:
                65280,

            fields: [

                {
                    name: "Python IP",
                    value: String(ip),
                    inline: false
                }

            ],

            footer: {

                text:
                    new Date()
                        .toLocaleString()

            }

        }

    ]
};

return msg;

let ip = null;
try {
    ip = (msg.payload && msg.payload.ip) ? msg.payload.ip : (global.get("python_ip", "file") || global.get("python_ip") || null);
} catch (e) {
    ip = (msg.payload && msg.payload.ip) ? msg.payload.ip : (global.get("python_ip") || null);
}
if (ip) {
    try {
        global.set("python_ip", ip, "file");
    } catch (e) {
        global.set("python_ip", ip);
    }
}
msg.payload = { ip: ip };
msg.stream_url = ip ? `http://${ip}:5000/stream` : "";
node.warn("python_online received IP: " + (ip || 'null'));
return msg;

let ip = null;
try {
    ip = global.get("python_ip", "file") || global.get("python_ip") || null;
} catch (e) {
    ip = global.get("python_ip") || null;
}
if (!ip) {
    return null;
}
msg.payload = { ip: ip };
msg.stream_url = `http://${ip}:5000/stream`;
return msg;

let data = msg.payload;

// =========================
// 防呆
// =========================
if (!data) return null;

// =========================
// current 防呆
// =========================
if (!data.current) {
    data.current = {};
}

// =========================
// today_stats 防呆
// =========================
if (!data.today_stats) {
    data.today_stats = {};
}

// =========================
// 統一補值
// =========================
let stats = data.today_stats;

stats.walk = stats.walk || 0;
stats.walk_time = stats.walk_time || 0;

stats.lick = stats.lick || 0;
stats.lick_time = stats.lick_time || 0;

stats.scratch = stats.scratch || 0;
stats.scratch_time = stats.scratch_time || 0;

stats.shake = stats.shake || 0;
stats.shake_time = stats.shake_time || 0;

stats.stop = stats.stop || 0;
stats.stop_time = stats.stop_time || 0;
stats.not_detected_time = stats.not_detected_time || 0;

stats.active_time = stats.active_time || 0;
stats.rest_time = stats.rest_time || 0;

// =========================
// behavior_log 修正
// =========================
if (Array.isArray(data.behavior_log)) {

    data.behavior_log = data.behavior_log.map(item => {

        return {
            behavior: item.behavior || "unknown",
            time: item.time || "--:--",
            duration: item.duration || 0,
            emoji: getEmoji(item.behavior)
        };

    });

} else {

    data.behavior_log = [];

}

// =========================
// current emoji
// =========================
if (!data.current.emoji) {

    data.current.emoji =
        getEmoji(data.current.behavior);

}

// =========================
// timestamp 防呆
// =========================
if (!data.current.timestamp) {

    data.current.timestamp =
        new Date().toLocaleTimeString();

}

// =========================
// health score 計算
// =========================

let active =
    Number(stats.active_time || 0);

let rest =
    Number(stats.rest_time || 0);

let total = active + rest;

let abnormal =

    Number(stats.lick_time || 0) +
    Number(stats.scratch_time || 0) +
    Number(stats.shake_time || 0);

let abnormal_ratio =
    total > 0 ? abnormal / total : 0;

let rest_ratio =
    total > 0 ? rest / total : 0;

let stop_ratio =
    total > 0
    ? Number(stats.stop_time || 0) / total
    : 0;

let inactivity_penalty =
    stop_ratio > 0.5 ? 1 : 0;

let health_score = Math.max(
    0,
    Math.round(
        100
        - abnormal_ratio * 60
        - rest_ratio * 15
        - inactivity_penalty * 20
    )
);

// =========================
// CSV 寫入節流
// 每 60 秒才寫一次
// =========================

let now = Date.now();

let lastCsvTime =
    context.get("lastCsvTime") || 0;

let csvInterval =
    5 * 1000;

let shouldWriteCsv =
    now - lastCsvTime >= csvInterval;

if (shouldWriteCsv) {

    context.set(
        "lastCsvTime",
        now
    );

}

// =========================
// CSV payload
// =========================

let csvPayload = {

    timestamp:
        new Date().toLocaleString('zh-TW'),

    walk:
        Number(stats.walk || 0),

    walk_time:
        Number(stats.walk_time || 0),

    lick:
        Number(stats.lick || 0),

    lick_time:
        Number(stats.lick_time || 0),

    scratch:
        Number(stats.scratch || 0),

    scratch_time:
        Number(stats.scratch_time || 0),

    shake:
        Number(stats.shake || 0),

    shake_time:
        Number(stats.shake_time || 0),

    stop:
        Number(stats.stop || 0),

    stop_time:
        Number(stats.stop_time || 0),

    not_detected_time:
        Number(stats.not_detected_time || 0),

    active_time:
        active,

    rest_time:
        rest,

    activity_score:
        Number(data.activity_score || 0),

    health_score:
        health_score
};

// =========================
// 主輸出
// =========================

msg.payload = data;

return [

    msg,

    msg,

    msg,

    msg,

    {
        payload:
            data.activity_score || 0
    },

    shouldWriteCsv
        ? {
            payload: csvPayload
        }
        : null
];

// =========================
// emoji helper
// =========================

function getEmoji(behavior) {

    switch (behavior) {

        case "scratch":
            return "🐾";

        case "lick":
            return "🧼";

        case "walk":
            return "🚶";

        case "shake":
            return "🔄";
        case "stop":
            return "⏹";
        case "not":
            return "📷";

        default:
            return "🐱";
    }
}

let data = msg.payload;

if (!data || !data.today_stats) {
    return null;
}

let stats = data.today_stats;

// =========================
// 統計
// =========================
let total =
    stats.active_time +
    stats.rest_time;

let abnormal =
    stats.lick_time +
    stats.scratch_time +
    stats.shake_time;

let abnormal_ratio =
    total > 0
    ? abnormal / total
    : 0;

let rest_ratio =
    total > 0
    ? stats.rest_time / total
    : 0;

let stop_ratio =
    total > 0
    ? (stats.stop_time || 0) / total
    : 0;

// =========================
// inactivity：stop_time 超過 50% 才視為長時間靜止
// =========================
let inactivity_penalty =
    stop_ratio > 0.5 ? 1 : 0;

// =========================
// health score
// =========================
let score = 100
    - abnormal_ratio * 60
    - rest_ratio * 15
    - inactivity_penalty * 20;

score = Math.max(0, Math.round(score));

data.health_score = score;

// =========================
// alerts
// =========================
let alerts = [];

let level = "low";

let messages = [];

let suggestions = [];

let highlight = false;

// =========================
// scratch
// =========================
if (stats.scratch_time > 10) {

    messages.push(
        `🐾 搔抓 ${ stats.scratch_time.toFixed(1) } 秒`
    );

    suggestions.push(
        "可能皮膚問題"
    );

    level = "high";

    highlight = true;
}

// =========================
// lick
// =========================
if (stats.lick_time > 10) {

    messages.push(
        `🧼 舔舐 ${ stats.lick_time.toFixed(1) } 秒`
    );

    suggestions.push(
        "可能壓力或皮膚問題"
    );

    if (level !== "high") {

        level = "medium";
    }
}

// =========================
// shake
// =========================
if (stats.shake > 10) {

    messages.push(
        `🔄 甩頭 ${ stats.shake_time.toFixed(1) } 次`
    );

    suggestions.push(
        "可能耳朵問題"
    );

    if (level !== "high") {

        level = "medium";
    }
}

// =========================
// 長時間靜止（stop_time 超過 50%）
// =========================
if (stop_ratio > 0.5) {

    messages.push(
        `⏹ 靜止比例 ${ (stop_ratio * 100).toFixed(1) }%`
    );

    suggestions.push(
        "貓咪長時間靜止，活動力偏低"
    );

    highlight = true;
}

// =========================
// health score 過低
// =========================
if (score < 50) {

    messages.push(
        `⚠️ Health Score 過低(${ score })`
    );

    suggestions.push(
        "建議持續觀察"
    );

    level = "high";

    highlight = true;
}

// =========================
// 組 alert
// =========================
if (messages.length > 0) {

    alerts.push({

        level: level,

        highlight: highlight,

        title: "健康異常",

        message: messages.join(" ｜ "),

        suggestion: suggestions.join("、"),

        health_score: score,

        timestamp:
            new Date().toLocaleString()

    });
}

// =========================
// payload
// =========================
data.alerts = alerts;

msg.payload = data;

return msg;

// =========================
// Discord 健康警示
// =========================

msg.headers = {
    "Content-Type": "application/json"
};

msg.url = "https://discord.com/api/webhooks/1507070766271959061/bAa1Pf55ixg0bJmqeoJTQVdPt2ScMyITxYr4ukHof8IfBUC6hCaQqysnqkn8paCXQcjO";

// =========================
// alerts
// =========================
let alerts =
    msg.payload?.alerts || [];

// 沒警示
if (alerts.length === 0) {

    // 清空上次警示
    flow.set(
        "last_discord_alert",
        ""
    );

    return null;
}

// =========================
// 第一個 alert
// =========================
let alert = alerts[0];

// =========================
// alert key
// 去除數字避免狂刷
// =========================
let clean_message =
    (alert.message || "")
    .replace(/[0-9.]+/g, "");

let alert_key = [

    alert.level || "",

    alert.title || "",

    clean_message

].join("|");

// =========================
// 上次 alert
// =========================
let last_alert =
    flow.get("last_discord_alert")
    || "";

// 相同警示不發
if (last_alert === alert_key) {

    return null;
}

// 更新 alert
flow.set(
    "last_discord_alert",
    alert_key
);

// =========================
// color
// =========================
let color = 16776960;

switch (alert.level) {

    case "high":
        color = 16711680;
        break;

    case "medium":
        color = 16753920;
        break;

    default:
        color = 16776960;
}

// =========================
// Discord payload
// =========================
msg.payload = {

    username:
        "Cat Health Monitor",

    embeds: [

        {

            title:
                `🚨 ${ alert.title } `,

            description:
                alert.message,

            color:
                color,

            fields: [

                {
                    name:
                        "Health Score",

                    value:
                        String(
                            alert.health_score || 0
                        ),

                    inline:
                        true
                },

                {
                    name:
                        "警示等級",

                    value:
                        String(
                            alert.level || "unknown"
                        ),

                    inline:
                        true
                },

                {
                    name:
                        "建議",

                    value:
                        String(
                            alert.suggestion || "無"
                        ),

                    inline:
                        false
                }

            ],

            footer: {

                text:
                    alert.timestamp ||
                    new Date()
                        .toLocaleString()

            }

        }

    ]
};

return msg;
